mapper.select:
SELECT * FROM voj_contests
contest_name LIKE "%"#{keyword}"%"
ORDER BY contest_id DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE voj_contests 
SET contest_name = #{contestName}, contest_notes = #{contestNotes}, contest_start_time = #{startTime}, contest_end_time = #{endTime}, contest_mode = #{contestMode}, contest_problems = #{problems}, contest_status = #{status}, contest_scoring = #{scoring}, contest_penalty = #{penalty}, contest_freeze = #{freeze}, contest_is_rated = #{isRated}, contest_open_registration = #{openRegistration}
WHERE contest_id = #{contestId}
